**Target:** Add regression test for JWT expiry grace window boundary at -30s threshold.

**Invariants:**
- Grace window accepts tokens up to 30s past expiry
- Boundary at exactly -30s returns 200
- Beyond boundary at -31s returns 401

**Test cases:**
```javascript
describe('JWT expiry grace regression', () => {
  it('accepts token at exact -30s boundary', async () => {
    const token = createExpiredToken(-30000); // -30s in ms
    const response = await request(app).get('/api/protected').set('Authorization', `Bearer ${token}`);
    expect(response.status).toBe(200);
  });

  it('rejects token beyond -31s boundary', async () => {
    const token = createExpiredToken(-31000); // -31s in ms  
    const response = await request(app).get('/api/protected').set('Authorization', `Bearer ${token}`);
    expect(response.status).toBe(401);
  });

**Target**: Convert callback-style middleware to async/await while preserving `next(err)` error handling and execution order.

**Invariants**: 
- `next(err)` remains single error path
- Request validation → data load → not-found check → side effects → response order preserved
- Middleware signature unchanged for compatibility

**Pattern**:
```javascript
// Before
function middleware(req, res, next) {
  validateInput(req, (err) => {
    if (err) return next(err);
    db.findUser(req.userId, (err, user) => {
      if (err) return next(err);
      if (!user) return next(new NotFoundError());
      audit.log(req, () => {
        res.json(user);
      });
    });
  });
}

